452→.cm-reply-context-name {
453→    color: var(--accent-amber);
454→    font-weight: 600;
455→}
456→.cm-reply-context-dismiss {
457→    display: inline-flex;
458→    align-items: center;
459→    justify-content: center;
460→    width: 16px;
461→    height: 16px;
