515→        width: 18px;
516→        height: 18px;
517→    }
518→    .cm-username {
519→        font-size: 0.74rem;
520→        max-width: 100px;
521→        overflow: hidden;
522→        text-overflow: ellipsis;
523→        white-space: nowrap;
524→    }
525→    .cm-body {
526→        font-size: 0.8rem;
527→        line-height: 1.55;
